        let score = 0
        // Determine parity of nums[i]. 0 for even, 1 for odd.
        // Since all nums[i] >= 1, standard modulo works fine.
        let parity_i = (nums[i] % 2)

        for j in (i + 1)..(n - 1) {
            let parity_j = (nums[j] % 2)

            // Check if parities are different
            if parity_i != parity_j {
                score += 1
            }
        }
        answer[i] = score
    }

